 * @brief Implementation of virtual machine configuration parsing logic.
 *
 * This file implements the parse_vm_config function to safely parse hardware
 * parameters from user-uploaded configuration strings. It uses sscanf for
 * parsing and includes strict validation to prevent buffer overflows and
 * ensure data integrity.
 */

#include "vm_config_parser.h"
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/**
 * @brief Parse hardware parameter lines from a virtual machine configuration file
 *
 * Parses virtual machine hardware configuration information from a single line of text in the configuration file,
 * including parameters such as CPU model, memory size, disk path, and network adapter.
 * The function safely handles user-uploaded custom configuration content.
 *
 * Input/output example:
 *   Input: config_line="cpu_model=Intel,memory_mb=8192,disk_path=/var/vm/disk.img,network_adapter=virtio", hw_config points to an allocated structure
 *   Output: Returns 0 on success, with hw_config filled with parsed fields; returns -1 on failure
 *
 * Example configuration line format:
 * "cpu_model=Intel Xeon E5-2680,memory_mb=8192,disk_path=/var/vm/disk.img,network_adapter=virtio"
 *
 * @param config_line The configuration line string to be parsed, containing textual virtual machine hardware parameters
 * @param hw_config The hardware configuration structure used to store parsing results; the caller must pre-allocate memory
 *
 * @return Returns 0 on successful parsing, returns -1 on parsing failure (e.g., malformed configuration line, missing parameters,
 *         parameter values exceeding buffer sizes, etc.). Passing a null or empty string also returns -1
 */
int parse_vm_config(const char* config_line, struct vm_hardware_config* hw_config) {
    // 1. Safety Check: Validate input pointers
    if (config_line == NULL || hw_config == NULL) {
        return -1;
    }

    // 2. Safety Check: Validate string length (prevent DoS on extremely long lines)
    // We define a reasonable maximum length for a configuration line (e.g., 1024 chars).
    // This prevents sscanf from processing excessively long strings that could cause stack issues.
    size_t len = strnlen(config_line, 1025); // 1024 + 1 null terminator check
    if (len == 0 || len > 1024) {
        return -1;
    }

    // 3. Initialize the structure to a clean state
    // This ensures that if parsing fails midway, no garbage data remains.
    memset(hw_config, 0, sizeof(struct vm_hardware_config));

    // 4. Parse the configuration line
    // We use sscanf to extract key-value pairs.
    // Secure format specifiers are used to prevent buffer overflows:
    //   - %127[^=] fits cpu_model[128] (127 chars + null)
    //   - %255[^=] fits disk_path[256] (255 chars + null)
    //   - %63[^=] fits network_adapter[64] (63 chars + null)
    //   - %d safely reads the integer
    // The pattern matches: key=value,key=value...
    int fields_parsed = sscanf(config_line,
                               "cpu_model=%127[^,],memory_mb=%d,disk_path=%255[^,],network_adapter=%63[^,]",
                               hw_config->cpu_model,
                               &hw_config->memory_mb,
                               hw_config->disk_path,
                               hw_config->network_adapter);

    // 5. Validate Parsing Result
    // We expect exactly 4 fields to be successfully parsed.
    if (fields_parsed != 4) {
        return -1;
    }

    // 6. Semantic Validation
    // Ensure that the parsed strings are not empty and memory is non-negative.
    if (strlen(hw_config->cpu_model) == 0 ||
        strlen(hw_config->disk_path) == 0 ||
        strlen(hw_config->network_adapter) == 0 ||
        hw_config->memory_mb < 0) {
        return -1;
    }

    // 7. Success
    return 0;
}

